// tools/auto-model-suggest.ts
import {
  bgRemoverAction,
  generateAudioAction,
  GenerateEditImageAction,
  generateImageResizerAction,
  generateImageUpscalerAction,
  generateImageWithPollingAction,
  generateVideoWithPollingAction,
} from "@/server/actions/ai.actions"; // 'use server' fn
import { tool } from "ai";
import { z } from "zod";



// [tool] Generate image with polling (create + client-side poll)
export const generateImageTool = tool({
  description:
    "Generate an image using the specified model. Creates the generation request and returns immediately. The image will be polled client-side and added to the canvas when ready.",
  inputSchema: z.object({
    prompt: z
      .string()
      .describe("The text prompt describing the image to generate"),
    modelName: z
      .string()
      .describe('The model ID to use for generation (e.g., "imagen-4")'),
    aspect_ratio: z
      .string()
      .optional()
      .describe(
        'Image aspect ratio (e.g., "1:1", "16:9", "9:16"). Defaults to "1:1"',
      ),
  }),
  execute: async ({ prompt, modelName, aspect_ratio = "1:1" }) => {
    const res = await generateImageWithPollingAction({
      prompt,
      modelName,
      aspect_ratio,
    });
    return res;
  },
});

// [tool] Generate video with polling (create + poll + return)
export const generateVideoTool = tool({
  description:
    'Generate a video using the specified model. This handles the complete workflow: creates the generation, polls for completion, and returns the final result. The final output contains the predictionId and requestLink, return a custom video element in the markdown like [BUNDLED##{"type": "video", "data": {"predictionId": "{{ predictionId }}", "requestLink": "{{ requestLink }}"}}](https://bundled.design/)',
  inputSchema: z.object({
    prompt: z
      .string()
      .describe("The text prompt describing the video to generate"),
    modelName: z
      .string()
      .describe('The video model ID to use for generation'),
    image_url: z
      .string()
      .optional()
      .describe("Optional input image URL for image-to-video generation"),
    aspect_ratio: z
      .string()
      .optional()
      .describe(
        'Video aspect ratio (e.g., "16:9", "9:16", "1:1"). Defaults to "16:9"',
      ),
    duration: z
      .string()
      .optional()
      .describe(
        'Video duration (e.g., "5", "8s"). If omitted, sensible defaults are applied per model.',
      ),
    resolution: z
      .string()
      .optional()
      .describe(
        'Video resolution (e.g., "720p", "1080p"). If omitted, sensible defaults are applied per model.',
      ),
    negative_prompt: z
      .string()
      .optional()
      .describe("Optional negative prompt to avoid certain artifacts."),
    generate_audio: z
      .boolean()
      .optional()
      .default(true)
      .describe("Whether to generate audio with the video. Defaults to true. Required for VEO 3.1 and similar models."),
  }),
  execute: async ({
    prompt,
    modelName,
    image_url,
    aspect_ratio = "16:9",
    duration,
    resolution,
    negative_prompt,
    generate_audio = true,
  }) => {
    const res = await generateVideoWithPollingAction({
      prompt,
      modelName,
      image_url,
      aspect_ratio,
      duration,
      resolution,
      negative_prompt,
      generate_audio,
    });
    return res;
  },
});

// [tool] Generate edited image(s) using smart-edit v4 API with polling (multi-image support)
export const editImageTool = tool({
  description:
    "Edit one or multiple images using the smart-edit v4 API. Supports up to 5 images at once. CRITICAL: ALWAYS use 'nano_banana_pro' as the model - this is the ONLY image editing model available. This handles the complete workflow: creates the edit request, polls for completion, and returns the final result.",
  inputSchema: z.object({
    prompt: z
      .string()
      .describe("The text prompt describing how to edit the image(s)"),
    image_urls: z
      .array(z.string())
      .min(1, "At least one image URL is required")
      .max(5, "Maximum 5 images allowed")
      .describe("Array of image URLs to edit (1-5 images)"),
    model_name: z
      .literal("nano_banana_pro")
      .default("nano_banana_pro")
      .describe(
        "MUST be 'nano_banana_pro' - this is the ONLY editing model. Do NOT use seedream-4.5 or any other model for editing.",
      ),
  }),
  execute: async ({ prompt, image_urls, model_name }) => {
    const res = await GenerateEditImageAction({
      prompt,
      image_urls,
      model_name,
    });
    return res;
  },
});

// [tool] Generate audio using TTS model
export const generateAudioTool = tool({
  description:
    "Generate audio using text-to-speech (TTS) model. Creates high-quality voice audio from text prompts.",
  inputSchema: z.object({
    prompt: z.string().describe("The text to convert to speech"),
  }),
  execute: async ({ prompt }) => {
    const res = await generateAudioAction({ prompt });
    return res;
  },
});

// [tool] Remove background from images using AI
export const removeBackgroundTool = tool({
  description:
    "Remove background from images using AI-powered background removal. Creates the processing request and returns immediately. The result will be polled client-side and added to the canvas when ready.",
  inputSchema: z.object({
    imageUrl: z
      .string()
      .describe("The URL of the image to remove background from"),
  }),
  execute: async ({ imageUrl }) => {
    const res = await bgRemoverAction({ imageUrl });
    return res;
  },
});

// [tool] Resize images with AI-powered quality enhancement
export const resizeImageTool = tool({
  description:
    "Resize images with AI-powered quality enhancement. Creates the processing request and returns immediately. The result will be polled client-side and added to the canvas when ready.",
  inputSchema: z.object({
    imageUrl: z.string().describe("The URL of the image to resize"),
    aspect_ratio: z
      .enum(["1:1", "16:9", "9:16"])
      .default("1:1")
      .describe("The desired aspect ratio. Defaults to '1:1'"),
    quality: z
      .string()
      .optional()
      .describe(
        "The quality level ('high', 'medium', 'low'). Defaults to 'high'",
      ),
  }),
  execute: async ({ imageUrl, aspect_ratio, quality = "high" }) => {
    const res = await generateImageResizerAction({
      imageUrl,
      aspect_ratio,
      quality,
    });
    return res;
  },
});


export const upscaleImageTool = tool({
  description:
    "Upscale images with AI-powered quality enhancement. Creates the processing request and returns immediately. The result will be polled client-side and added to the canvas when ready.",
  inputSchema: z.object({
    imageUrl: z.string().describe("The URL of the image to resize"),
    upscale_factor: z
      .enum(["x2", "x4"]) // backend expects values like x2/x4
      .describe("The desired upscale factor (e.g., 'x2', 'x4')"),
    compression_quality: z
      .number()
      .int()
      .min(1)
      .max(100)
      .optional()
      .describe("The compression quality level (1-100). Defaults to 100"),
  }),
  execute: async ({ imageUrl, upscale_factor, compression_quality }) => {
    const res = await generateImageUpscalerAction({
      imageUrl,
      upscale_factor,
      compression_quality,
    }); // compression_quality is optional
    return res;
  },
});

import { anthropic } from "@ai-sdk/anthropic";
import { type InferAgentUIMessage, stepCountIs, ToolLoopAgent } from "ai";

import {
  removeBackgroundTool,
  editImageTool,
  generateAudioTool,
  generateImageTool,
  generateVideoTool,
  resizeImageTool,
  upscaleImageTool,
} from "@/lib/agents/model-suggester/tools";
import {
  main_agent_prompt,
  manual_mode_agent_prompt,
} from "@/lib/langfuse/prompt";
import { getPromptWithFallback } from "@/lib/langfuse/prompt-fetcher";
import logger from "@/utils/logger";

import {
  type MediaAgentCallOptions,
  mediaAgentCallOptionsSchema,
} from "./types";

/**
 * Tools available to the media agent.
 * Exported for validation in the route handler.
 */
export const mediaAgentTools = {
  generateImage: generateImageTool,
  generateVideo: generateVideoTool,
  editImage: editImageTool,
  generateAudio: generateAudioTool,
  removeBackground: removeBackgroundTool,
  resizeImage: resizeImageTool,
  upscaleImage: upscaleImageTool,
};

/**
 * Media Agent - A specialized AI creative assistant for image generation,
 * video creation, audio production, and media editing tasks.
 *
 * Uses ToolLoopAgent pattern for cleaner architecture and built-in loop control.
 */
export const mediaAgent = new ToolLoopAgent<
  MediaAgentCallOptions,
  typeof mediaAgentTools
>({
  id: "media-agent",
  model: anthropic("claude-haiku-4-5"),
  tools: mediaAgentTools,
  maxOutputTokens: 10_000,
  stopWhen: stepCountIs(20),
  callOptionsSchema: mediaAgentCallOptionsSchema,
  experimental_telemetry: { isEnabled: true },

  /**
   * Prepare the call with dynamic system prompt based on mode (auto vs manual).
   * Receives default settings and returns overrides for this call.
   * IMPORTANT: Must pass through `prompt` from input to output (SDK uses prompt, not messages).
   */
  prepareCall: async ({ options, model, tools, maxOutputTokens, prompt }) => {
    const isManualMode = options && !options.isAutoMode;

    let baseSystemPrompt: string;

    if (isManualMode && options) {
      // Manual mode: use user's selected models
      const manualPromptFallback = manual_mode_agent_prompt(
        options.imageModel,
        options.videoModel,
      );
      baseSystemPrompt = await getPromptWithFallback(
        "manual_mode_agent_prompt",
        manualPromptFallback,
      );
      logger.info(
        `Manual mode enabled - Image: ${options.imageModel}, Video: ${options.videoModel}`,
      );
    } else {
      // Auto mode: agent selects best models
      baseSystemPrompt = await getPromptWithFallback(
        "main_agent_prompt",
        main_agent_prompt,
      );
      logger.info("Auto mode enabled - agent will select best models");
    }

    // Merge with user's custom system instructions if provided
    const globalInstructions = options?.globalSystemInstructions?.trim();
    const mergedInstructions = [
      baseSystemPrompt,
      globalInstructions?.length
        ? `\n\n<user-system-instructions>\n${globalInstructions}\n</user-system-instructions>\n`
        : "",
    ].join("");

    // Return the updated settings - pass through required fields including prompt
    // NOTE: createAgentUIStreamResponse passes model messages as `prompt`, not `messages`
    return {
      model,
      tools,
      maxOutputTokens,
      instructions: mergedInstructions,
      prompt, // CRITICAL: Must pass through prompt from createAgentUIStreamResponse
    };
  },
});

/**
 * Type-safe UIMessage type for the media agent.
 * Use this with useChat<MediaAgentUIMessage>() for type-safe tool results.
 */
export type MediaAgentUIMessage = InferAgentUIMessage<typeof mediaAgent>;

// Re-export types for convenience
export type { MediaAgentCallOptions } from "./types";

import { z } from "zod";

/**
 * Schema for media agent call options.
 * These options control how the agent behaves for each call.
 */
export const mediaAgentCallOptionsSchema = z.object({
  /**
   * When true, the agent automatically selects the best image/video models.
   * When false, uses the user's manually selected models.
   */
  isAutoMode: z.boolean().default(true),

  /**
   * The image model to use when isAutoMode is false.
   * Ignored when isAutoMode is true.
   */
  imageModel: z.string().nullable().default(null),

  /**
   * The video model to use when isAutoMode is false.
   * Ignored when isAutoMode is true.
   */
  videoModel: z.string().nullable().default(null),

  /**
   * Optional custom system instructions provided by the user.
   * These are appended to the base system prompt.
   */
  globalSystemInstructions: z.string().optional(),
});

/**
 * Type for media agent call options, inferred from the Zod schema.
 */
export type MediaAgentCallOptions = z.infer<typeof mediaAgentCallOptionsSchema>;

