   458→            eventProperties,
   459→          );
   460→        } catch (phErr: any) {
   461→          // PostHog capture failed silently
   462→        }
   463→
   464→        if (prediction.status === "succeeded") {
   465→          // step 12 is return the final result
   466→          const finalResult = {
   467→            success: true,
   468→            predictionId,
   469→            status: "succeeded",
   470→            output: prediction.output || [],
   471→            model_name,
