import logger from "@/utils/logger";

/**
 * Maps error messages to user-friendly messages
 */
export function getErrorMessage(error: unknown): string {
  const errorMessage = error instanceof Error ? error.message : "";

  if (errorMessage.includes("rate limit")) {
    return "I'm experiencing high demand right now. Please try again in a moment.";
  }

  if (errorMessage.includes("timeout")) {
    return "The request took too long. Please try a simpler question.";
  }

  if (errorMessage.includes("context length")) {
    return "The conversation is too long. Please start a new chat.";
  }

  return "Sorry, I am not able to respond right now. Please try again later.";
}

/**
 * Logs agent errors with structured context
 */
export function logAgentError(
  error: unknown,
  context: { requestId: string; [key: string]: unknown },
): void {
  if (error instanceof Error) {
    logger.error(
      `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${context.requestId}, stack=${error.stack}`,
    );
  } else {
    logger.error(
      `Unknown stream error: error=${JSON.stringify(error)}, requestId=${context.requestId}`,
    );
  }
}

/**
 * Factory for creating onError callback for agent streams
 */
export function createStreamErrorHandler(context: { requestId: string }) {
  return (error: unknown): string => {
    logAgentError(error, context);
    return getErrorMessage(error);
  };
}

