import type { UIMessage } from "ai";

/**
 * Extracts text content from a UIMessage
 */
export function extractTextFromUiMessage(
  message: UIMessage,
): string | undefined {
  return extractTextFromParts(message.parts);
}

/**
 * Extracts text content from message parts
 */
export function extractTextFromParts(
  parts: UIMessage["parts"],
): string | undefined {
  const chunks: string[] = [];
  for (const part of parts) {
    if (part.type === "text") {
      chunks.push(part.text);
    }
  }
  const text = chunks.join("");
  return text.trim().length ? text : undefined;
}

/**
 * Extracts the latest user text from a list of UIMessages
 */
export function extractLatestUserTextFromUiMessages(
  messages: UIMessage[],
): string | undefined {
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    const msg = messages[i];
    if (msg.role !== "user") continue;
    const text = extractTextFromUiMessage(msg);
    if (text) return text;
  }
  return;
}

/**
 * Summarizes message parts for logging
 */
export function summarizeParts(parts: UIMessage["parts"]): string {
  const counts = new Map<string, number>();
  for (const part of parts) {
    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
  }
  const summary = [...counts.entries()]
    .map(([type, count]) => `${type}:${count}`)
    .join(", ");

  return summary.length ? `parts(${summary})` : "parts(empty)";
}

