    mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
  });

  const start = Date.now();
  let attempt = 0;

  // [debug] Log polling configuration
  logger.debug("[POLLING] Polling configuration:", {
    predictionId,
    provider,
    baseUrl,
    directApiCall: provider === "replicate",
  });

  // Polling starts immediately (no initial delay)
  // Direct Replicate API calls help reduce rate limiting by avoiding internal API overhead

  while (attempt < maxAttempts && Date.now() - start < totalTimeoutMs) {
    attempt += 1;

    logger.debug(`[POLLING] Attempt ${attempt}/${maxAttempts}`, {
      predictionId,
      provider,
      timeElapsed: `${Math.round((Date.now() - start) / 1000)}s`,
    });

    try {
      // [debug] Making direct API call to Replicate
      logger.debug(
        `[POLLING] Making direct API call to Replicate for prediction: ${predictionId}`,
      );

      let data: PredictionResponse;

      if (provider === "replicate") {
        // Call Replicate API directly (like the test route)
        const prediction = await replicate.predictions.get(predictionId);
        data = prediction as unknown as PredictionResponse;
      } else {
        // Fallback to internal API route for other providers
        const pollUrl = `${baseUrl}/api/image/prediction/${encodeURIComponent(predictionId)}?provider=${encodeURIComponent(provider)}`;
        logger.debug(`[POLLING] Using internal API route: ${pollUrl}`);

        const res = await fetch(pollUrl, {
          method: "GET",
          headers: {
            Accept: "application/json",
            ...(cookie ? { Cookie: cookie } : {}),
          },
          cache: "no-store",
        });

        if (!res.ok) {
          throw new Error(
            `API request failed: ${res.status} ${res.statusText}`,
          );
        }

        data = (await res.json()) as PredictionResponse;
      }

      // [debug] Log the full response structure
      logger.debug("[POLLING] Full response data:", {
        data,
        dataKeys: Object.keys(data || {}),
        dataType: typeof data,
        isArray: Array.isArray(data),
      });

      // [debug] Polling JSON payload
      logger.debug("[POLLING] Response summary:", {
        status: data?.status,
        id: data?.id,
        hasOutput: !!data?.output,
        hasError: !!data?.error,
        created_at: data?.created_at,
      });

      if (data?.status === "succeeded") {
        // [info] Completed: prediction succeeded
        logger.debug("[POLLING] SUCCESS: Prediction completed successfully", {
          predictionId,
          finalStatus: data.status,
          outputCount: Array.isArray(data.output)
            ? data.output.length
            : "not array",
          duration: `${Math.round((Date.now() - start) / 1000)}s`,
        });
        return data;
      }

      if (data?.status === "failed") {
        // [error] Completed: prediction failed
        logger.debug("[POLLING] FAILED: Prediction failed", {
          predictionId,
          error: data?.error,
          finalStatus: data.status,
          duration: `${Math.round((Date.now() - start) / 1000)}s`,
        });
        return data;
      }

      // Continue polling for other statuses
      const delay = fixedInterval
        ? initialDelayMs // Fixed interval: always use initialDelayMs
        : backoff(attempt - 1, initialDelayMs, maxDelayMs); // Exponential backoff

      const timeElapsed = Math.round((Date.now() - start) / 1000);
      logger.debug(
        `[POLLING] Status: "${data?.status}" - continuing to poll...`,
        {
          predictionId,
          attempt,
          nextDelay: `${delay}ms (${delay / 1000}s)`,
          mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
          timeElapsed: `${timeElapsed}s`,
          nextPollAt: `${timeElapsed + delay / 1000}s`,
        },
      );

      logger.debug(
        `[POLLING] Sleeping for ${delay}ms (${delay / 1000}s) before next poll...`,
      );
      await sleep(delay);
      logger.debug(
        `[POLLING] Woke up after ${delay}ms sleep. Time elapsed: ${Math.round((Date.now() - start) / 1000)}s`,
      );
    } catch (error) {
      // [warn] network or parse error, continue with backoff
      logger.debug(`[POLLING] Request failed on attempt ${attempt}:`, {
        error: error instanceof Error ? error.message : error,
        errorType:
          error instanceof Error ? error.constructor.name : typeof error,
        predictionId,
        provider,
        attempt,
      });

      if (attempt >= maxAttempts) {
        logger.debug("[POLLING] Max attempts reached, giving up");
        throw error;
      }

      const delay = fixedInterval
        ? initialDelayMs
        : backoff(attempt - 1, initialDelayMs, maxDelayMs);
      logger.debug(`[POLLING] Waiting ${delay}ms before retry...`, {
        mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
      });
      await sleep(delay);
    }
  }

  // [error] Timed out
  logger.debug(
    `[POLLING] TIMEOUT: Polling timed out after ${maxAttempts} attempts`,
    {
      predictionId,
      totalTime: `${Math.round((Date.now() - start) / 1000)}s`,
      maxAttempts,
      totalTimeoutMs: `${totalTimeoutMs / 1000}s`,
    },
  );

  return { id: predictionId, status: "failed", error: "Polling timed out" };
}

