 * Schema for media agent call options.
 * These options control how the agent behaves for each call.
 */
export const mediaAgentCallOptionsSchema = z.object({
  /**
   * When true, the agent automatically selects the best image/video models.
   * When false, uses the user's manually selected models.
   */
  isAutoMode: z.boolean().default(true),

  /**
   * The image model to use when isAutoMode is false.
   * Ignored when isAutoMode is true.
   */
  imageModel: z.string().nullable().default(null),

  /**
   * The video model to use when isAutoMode is false.
   * Ignored when isAutoMode is true.
   */
  videoModel: z.string().nullable().default(null),

  /**
   * Optional custom system instructions provided by the user.
   * These are appended to the base system prompt.
   */
  globalSystemInstructions: z.string().optional(),
});

/**
 * Type for media agent call options, inferred from the Zod schema.
 */
export type MediaAgentCallOptions = z.infer<typeof mediaAgentCallOptionsSchema>;

