import {
  observe,
  updateActiveObservation,
  updateActiveTrace,
} from "@langfuse/tracing";
import { trace } from "@opentelemetry/api";
import {
  createAgentUIStreamResponse,
  createUIMessageStream,
  createUIMessageStreamResponse,
  TypeValidationError,
  type UIMessage,
  validateUIMessages,
} from "ai";
import type { NextRequest } from "next/server";
import { after } from "next/server";
import { authenticateUser } from "@/lib/auth/utils";
import {
  type MediaAgentCallOptions,
  mediaAgent,
  mediaAgentTools,
} from "@/lib/agents/media-agent";
import {
  createChat,
  getChatById,
} from "@/server/database/repo/postgress-repo-functions/chat.repo";
import {
  loadChatMessages,
  saveChatMessage,
} from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
import { findProjectByIdForUser } from "@/server/database/repo/postgress-repo-functions/imageEditorProjects.repo";
import logger from "@/utils/logger";
import { langfuseSpanProcessor } from "../../../../../instrumentation";

// Allow streaming up to 180s
export const maxDuration = 180;

const handler = async (req: NextRequest) => {
  const requestId = crypto.randomUUID();
  const { id: userId } = await authenticateUser(requestId);

  // Get the last message, projectId, and optionally chatId from client
  const {
    message,
    id: projectId,
    chatId: clientChatId,
    globalSystemInstructions,
    modelSelection,
  }: {
    message: UIMessage;
    id: string;
    chatId?: string;
    globalSystemInstructions?: string;
    modelSelection?: {
      isAutoMode: boolean;
      imageModel: string | null;
      videoModel: string | null;
    };
  } = await req.json();

  // Log model selection for debugging
  logger.info(`Model selection received: ${JSON.stringify(modelSelection)}`);

  const initialTraceInput =
    extractTextFromUiMessage(message) ??
    `[${message.role}] ${summarizeParts(message.parts)}`;

  try {
    // Verify project exists and user owns it
    const project = await findProjectByIdForUser({ projectId, userId });
    if (!project) {
      logger.error("Project not found or access denied");
      return new Response(
        JSON.stringify({ error: "Project not found or access denied" }),
        { status: 403, headers: { "Content-Type": "application/json" } },
      );
    }

    // Resolve or create chat
    // Client always sends a chatId (either existing or pre-generated UUID)
    let chat: Awaited<ReturnType<typeof getChatById>> | null = null;
    let previousMessages: UIMessage[] = [];

    if (!clientChatId) {
      // Chat not found with provided chatId - create a new chat
      logger.error("No chatId provided by client", {
        requestId,
        userId,
        projectId,
      });
      return new Response(
        JSON.stringify({
          error:
            "chatId is required but was not provided. This usually indicates an outdated or misconfigured client. Please refresh the page or update the client and try again.",
        }),
        {
          status: 400,
          headers: { "Content-Type": "application/json" },
        },
      );
    }

    // Update Langfuse trace with context (now that we have a chat/session id)
    updateActiveTrace({
      name: "agent-chat-message",
      sessionId: clientChatId,
      userId,
      input: initialTraceInput,
      metadata: {
        projectId,
        requestId,
        isManualMode: modelSelection ? !modelSelection.isAutoMode : false,
      },
    });

    updateActiveObservation({
      input: initialTraceInput,
    });

    // Try to get existing chat
    chat = await getChatById({ chatId: clientChatId, userId });

    if (chat) {
      // Existing chat - load messages
      previousMessages = await loadChatMessages(chat.id, userId);
    } else {
      // No chatId provided - create a new chat

      chat = await createChat({
        id: clientChatId, // Use client's pre-generated ID
        projectId,
        userId,
        title: "New Chat",
      });

      if (!chat) {
        logger.error("Failed to create chat");
        return new Response(
          JSON.stringify({ error: "Failed to create chat" }),
          { status: 500, headers: { "Content-Type": "application/json" } },
        );
      }
      // No previous messages for new chat
      previousMessages = [];
    }

    // Track continuation message ID to maintain consistent IDs across multi-step tool execution
    // When client sends an assistant message (via sendAutomaticallyWhen), we reuse its ID
    // so all steps share the same message ID (like DB upsert pattern)
    let continuationMessageId: string | undefined;

    // Build messages array for LLM based on incoming message role
    let messages: UIMessage[];

    if (message.role === "user") {
      // User message: append to conversation history
      messages = [...previousMessages, message];
      logger.info(`User message received, total messages: ${messages.length}`);
    } else if (message.role === "assistant") {
      // Assistant message sent by client's sendAutomaticallyWhen
      // Preserve the client's message ID for consistency
      continuationMessageId = message.id;
      // Use only previous messages (new assistant message will be generated)
      messages = previousMessages;
      logger.info(
        `Assistant message received (auto-continuation), using ${messages.length} previous messages, continuationId: ${continuationMessageId}`,
      );
    } else {
      // Unexpected role (system, etc.)
      logger.warn(`Unexpected message role: ${message.role}`);
      messages = [...previousMessages, message];
    }

    const bestTraceInput =
      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;

    updateActiveObservation({ input: bestTraceInput });
    updateActiveTrace({ input: bestTraceInput });

    // Validate messages against tool schemas to ensure compatibility
    let validatedMessages: UIMessage[];
    try {
      validatedMessages = await validateUIMessages({
        messages,
        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
        tools: mediaAgentTools as any,
      });
    } catch (error) {
      if (error instanceof TypeValidationError) {
        // Log validation error for monitoring
        logger.warn(
          `Message validation failed, starting with only new message: ${error.message}`,
        );
        // If validation fails (e.g., old tool schemas), start fresh with just the new message
        validatedMessages = [message];
      } else {
        throw error;
      }
    }

    // Save user message to database immediately (before streaming)
    // Assistant messages are saved in onFinish callback after streaming completes
    if (message.role === "user") {
      await saveChatMessage({ message, chatId: chat.id, userId });
      logger.info(`User message saved: ${message.id}`);
    }
    // Build agent call options from request
