import {
  observe,
  updateActiveObservation,
  updateActiveTrace,
} from "@langfuse/tracing";
import { trace } from "@opentelemetry/api";

// Re-export observe for convenience
export { observe };

type TraceParams = Parameters<typeof updateActiveTrace>[0];
type ObservationParams = Parameters<typeof updateActiveObservation>[0];

/**
 * Wrapper for Langfuse trace updates with consistent error handling
 */
export function updateAgentTrace(params: TraceParams): void {
  updateActiveTrace(params);
}

/**
 * Wrapper for Langfuse observation updates with consistent error handling
 */
export function updateAgentObservation(params: ObservationParams): void {
  updateActiveObservation(params);
}

/**
 * Helper to end the active OpenTelemetry span
 */
export function endActiveSpan(): void {
  trace.getActiveSpan()?.end();
}

